Method.Source:
[SysClientCacheDataMethodAttribute(true)]
public static display DimensionValue getCropYearETG(InventTrans _inventTrans)
{

    // Feature toggle 
    if (ETGCanadaParameters::find().EnableCropYearItem==NoYes::No)

    {
        return "";
    }

    try
    {
        InventTransOrigin inventTransOrigin = _inventTrans.inventTransOrigin();
        if (!inventTransOrigin)
        {
            return "";
        }

        DimensionDefault dimDefault = InventTrans::getDefaultDimensionETG(inventTransOrigin);

        if (dimDefault)
        {
            return ETGFixedAssetFinancialsDimensions::getDimensionDisplayValueCodeOnlyETG(dimDefault, ETGCanadaParameters::find().CropYear);

        }
        else
        {
            return "";
        }
    }
    catch (Exception::Error)
    {
        return "";
    }
    catch
    {
        return "";
    }


}
